/**
 * 同步存储模块
 * 适用于需要即时响应和数据一致性的场景
 * 特点：快速读取、阻塞式写入、数据实时可见
 */

import { StorageConfig, StorageKeys } from './config.js'

class SyncStorage {
  constructor() {
    this.cache = new Map()
    this.initialized = false
  }

  init() {
    if (this.initialized) return
    StorageConfig.syncKeys.forEach(key => {
      try {
        const value = uni.getStorageSync(key)
        if (value !== null && value !== undefined && value !== '') {
          this.cache.set(key, value)
        }
      } catch (e) {
        console.warn(`[SyncStorage] 初始化缓存失败: ${key}`, e)
      }
    })
    this.initialized = true
  }

  set(key, value) {
    try {
      uni.setStorageSync(key, value)
      this.cache.set(key, value)
      return { success: true, error: null }
    } catch (e) {
      console.error(`[SyncStorage] 写入失败: ${key}`, e)
      return { success: false, error: e }
    }
  }

  get(key, defaultValue = null) {
    try {
      if (this.cache.has(key)) {
        return this.cache.get(key)
      }
      const value = uni.getStorageSync(key)
      if (value !== null && value !== undefined && value !== '') {
        this.cache.set(key, value)
        return value
      }
      return defaultValue
    } catch (e) {
      console.error(`[SyncStorage] 读取失败: ${key}`, e)
      return defaultValue
    }
  }

  remove(key) {
    try {
      uni.removeStorageSync(key)
      this.cache.delete(key)
      return { success: true, error: null }
    } catch (e) {
      console.error(`[SyncStorage] 删除失败: ${key}`, e)
      return { success: false, error: e }
    }
  }

  has(key) {
    return this.cache.has(key) || uni.getStorageSync(key) !== null
  }

  clear() {
    try {
      StorageConfig.syncKeys.forEach(key => {
        uni.removeStorageSync(key)
        this.cache.delete(key)
      })
      return { success: true, error: null }
    } catch (e) {
      console.error('[SyncStorage] 清空失败', e)
      return { success: false, error: e }
    }
  }

  getUserPreferences() {
    return this.get(StorageKeys.USER_PREFERENCES, {
      theme: 'light',
      autoPlay: true,
      downloadQuality: 'high'
    })
  }

  setUserPreferences(prefs) {
    const current = this.getUserPreferences()
    const merged = { ...current, ...prefs }
    return this.set(StorageKeys.USER_PREFERENCES, merged)
  }

  getSearchHistory() {
    const history = this.get(StorageKeys.SEARCH_HISTORY, '[]')
    try {
      return JSON.parse(history)
    } catch {
      return []
    }
  }

  addSearchHistory(keyword) {
    if (!keyword || !keyword.trim()) return
    let history = this.getSearchHistory()
    history = history.filter(item => item !== keyword)
    history.unshift(keyword)
    if (history.length > 10) {
      history = history.slice(0, 10)
    }
    return this.set(StorageKeys.SEARCH_HISTORY, JSON.stringify(history))
  }

  clearSearchHistory() {
    return this.set(StorageKeys.SEARCH_HISTORY, '[]')
  }

  getUIState() {
    return this.get(StorageKeys.UI_STATE, {
      lastTab: 'index',
      scrollPosition: {},
      expandedSections: {}
    })
  }

  setUIState(state) {
    const current = this.getUIState()
    return this.set(StorageKeys.UI_STATE, { ...current, ...state })
  }

  getSession() {
    return this.get(StorageKeys.USER_SESSION, {
      isLoggedIn: false,
      lastLoginTime: null,
      userId: null
    })
  }

  setSession(session) {
    const current = this.getSession()
    return this.set(StorageKeys.USER_SESSION, { ...current, ...session })
  }

  updateLastVisitTime() {
    return this.set(StorageKeys.LAST_VISIT_TIME, Date.now())
  }

  getLastVisitTime() {
    return this.get(StorageKeys.LAST_VISIT_TIME, null)
  }

  getStorageInfo() {
    try {
      const info = uni.getStorageInfoSync()
      return {
        keys: info.keys,
        currentSize: info.currentSize,
        limitSize: info.limitSize,
        usagePercent: ((info.currentSize / info.limitSize) * 100).toFixed(2)
      }
    } catch (e) {
      return null
    }
  }
}

const syncStorage = new SyncStorage()
syncStorage.init()

export default syncStorage
